package cl.duoc.vetcontrol.notificacion.controller;
import cl.duoc.vetcontrol.notificacion.dto.NotificacionRequest; import cl.duoc.vetcontrol.notificacion.model.Notificacion; import cl.duoc.vetcontrol.notificacion.service.NotificacionService; import jakarta.validation.Valid; import org.springframework.http.*; import org.springframework.web.bind.annotation.*; import java.util.List;
@RestController @RequestMapping("/api/v1/notificaciones")
public class NotificacionController { private final NotificacionService service; public NotificacionController(NotificacionService service){this.service=service;} @GetMapping public ResponseEntity<List<Notificacion>> all(){return ResponseEntity.ok(service.all());} @PostMapping public ResponseEntity<Notificacion> create(@Valid @RequestBody NotificacionRequest r){return ResponseEntity.status(HttpStatus.CREATED).body(service.create(r));} }
